+
+function getRuntimeDepsFileSignature(filePath: string): string | null {
+  try {
+    const stat = fs.statSync(filePath, { bigint: true });
+    if (!stat.isFile()) {
+      return null;
+    }
+    return [
+      stat.dev.toString(),
+      stat.ino.toString(),
+      stat.size.toString(),
+      stat.mtimeNs.toString(),
+    ].join(":");
+  } catch {
+    return null;
+  }
+}
