+
+function rememberRuntimeDepsCacheEntry<T>(cache: Map<string, T>, key: string, value: T): void {
+  if (cache.size >= MAX_RUNTIME_DEPS_FILE_CACHE_ENTRIES && !cache.has(key)) {
+    cache.delete(cache.keys().next().value as string);
+  }
+  cache.set(key, value);
+}
